function solve(n, edges, k) {
    let max_time = 0;
    if (edges.length > 0) {
        for (let edge of edges) {
            if (edge[2] > max_time) {
                max_time = edge[2];
            }
        }
    }

    function countComponents(t) {
        let parent = Array.from({ length: n }, (_, i) => i);
        let rank = new Array(n).fill(0);
        let components = n;

        function find(x) {
            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        function union(x, y) {
            let rx = find(x);
            let ry = find(y);
            if (rx === ry) return false;
            if (rank[rx] < rank[ry]) {
                parent[rx] = ry;
            } else if (rank[rx] > rank[ry]) {
                parent[ry] = rx;
            } else {
                parent[ry] = rx;
                rank[rx]++;
            }
            components--;
            return true;
        }

        for (let edge of edges) {
            const time = edge[2];
            if (time > t) {
                const u = edge[0];
                const v = edge[1];
                union(u, v);
            }
        }

        return components;
    }

    let low = 0;
    let high = max_time;

    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        let comp = countComponents(mid);
        if (comp >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    return low;
}
